output.sparql:
PREFIX wd: <http://www.wikidata.org/entity/>
PREFIX rdfs: <http://www.w3.org/2000/01/rdf-schema#>
PREFIX wdt: <http://www.wikidata.org/prop/direct/>
PREFIX xsd: <http://www.w3.org/2001/XMLSchema#>
SELECT DISTINCT ?office ?officeLabel WHERE {
  ?office wdt:P749 wd:Q1355327 .
  OPTIONAL {
    ?office wdt:P576 ?dissolved .
  }
  FILTER(! BOUND(?dissolved) || ?dissolved > "2021-01-20T00:00:00Z" ^^ xsd:dateTime)
  OPTIONAL {
    ?office rdfs:label ?officeLabel
    FILTER(LANG(?officeLabel) = "en")
    .
  }
}
ORDER BY ?officeLabel
